mapper.select:
SELECT *
FROM planner_memo
WHERE id = #{memoId}
  AND user_id = #{userId}
  AND deleted_at IS NULL

mapper.update:
UPDATE planner_memo
SET deleted_at = CURRENT_TIMESTAMP
WHERE id = #{memoId}
  AND user_id = #{userId}
  AND deleted_at IS NULL

UPDATE planner_schedule_item
SET deleted_at = CURRENT_TIMESTAMP
WHERE id = #{itemId}
  AND user_id = #{userId}
  AND deleted_at IS NULL

mapper.select:
SELECT * FROM planner_schedule_reminder WHERE schedule_item_id IN
#{itemId}
ORDER BY remind_at ASC, id ASC

mapper.delete:
DELETE psr
FROM planner_schedule_reminder psr
INNER JOIN planner_schedule_item psi ON psi.id = psr.schedule_item_id
WHERE psr.schedule_item_id = #{itemId}
  AND psi.user_id = #{userId}

mapper.select:
SELECT COUNT(*)
FROM planner_schedule_item
WHERE user_id = #{userId}
  AND deleted_at IS NULL
  AND status != 'CANCELED'
  AND start_at IS NOT NULL
  AND end_at IS NOT NULL
  AND start_at < #{endAt}
  AND end_at > #{startAt}

  AND id != #{excludeItemId}

SELECT COUNT(*)
FROM application_case
WHERE id = #{applicationCaseId}
  AND user_id = #{userId}
  AND deleted_at IS NULL

SELECT COUNT(*)
FROM fit_analysis fa
INNER JOIN application_case ac ON ac.id = fa.application_case_id
WHERE fa.id = #{fitAnalysisId}
  AND ac.user_id = #{userId}
  AND ac.deleted_at IS NULL
